/**
 * Projectile fired by a tower. Pooled for zero-GC performance.
 */
static class Bullet {
    Vector2 pos = new Vector2();
    Vector2 vel = new Vector2();
    float damage;
    float aoeRadius;
    float laserBonus;
    float slowFactor;
    float life;
    boolean dead;
    GameObject gameObject;

    public void reset(float x, float y, float vx, float vy, float dmg, float aoe, float laser, float slow) {
        pos.set(x, y);
        vel.set(vx, vy);
        damage = dmg;
        aoeRadius = aoe;
        laserBonus = laser;
        slowFactor = slow;
        life = 3.0f;
        dead = false;
    }

    public void update(float dt) {
        if (dead) return;
        life -= dt;
        if (life <= 0) {
            dead = true;
            recycle();
            return;
        }

        pos.x += vel.x * dt;
        pos.y += vel.y * dt;
        if (gameObject != null) {
            gameObject.getTransform().setPosition(pos.x, pos.y);
        }

        for (Enemy e : TdGameWorld.enemies) {
            float dx = pos.x - e.pos.x;
            float dy = pos.y - e.pos.y;
            if (dx * dx + dy * dy < (e.radius + 4) * (e.radius + 4)) {
                hit(e);
                dead = true;
                recycle();
                return;
            }
        }
    }

    public void hit(Enemy e) {
        float dmg = damage;
        if (laserBonus > 0) dmg += laserBonus;
        e.hp -= dmg;
        if (slowFactor > 0) e.slowFactor = Math.min(e.slowFactor, slowFactor);

        if (aoeRadius > 0) {
            for (Enemy ne : TdGameWorld.enemies) {
                if (ne != e) {
                    float dx = e.pos.x - ne.pos.x;
                    float dy = e.pos.y - ne.pos.y;
                    if (dx * dx + dy * dy <= aoeRadius * aoeRadius) {
                        ne.hp -= dmg * 0.5f;
                    }
                }
            }
        }
    }

    public void recycle() {
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        if (gameObject != null) {
            gameObject.setActive(false);
            app.bulletGoPool.release(gameObject);
            gameObject = null;
        }
        app.bulletDataPool.release(this);
    }
}
/**
 * Enemy instance on a path route.
 */

enum EnemyState {
    MOVE_TO_BASE,
    STEAL,
    FLEE,
    DEAD
}

static class Enemy {
    Vector2 pos;
    float hp, maxHp;
    float speed;
    float radius;
    float slowFactor = 1f;
    boolean reachedEnd;

    EnemyDef enemyDef;
    int orbsCarried = 0;

    PathRoute inboundRoute;   // route from spawn to base
    PathRoute outboundRoute;  // route from base to exit (assigned after steal)
    PathRoute activeRoute;    // currently active route
    float routeProgress;
    GameObject gameObject;

    EnemyState state = EnemyState.MOVE_TO_BASE;
    boolean hasStolen = false;

    // Smooth turning state
    int currentSegment = 0;
    boolean isTurning = false;
    static final float TURN_DURATION = 0.2f;

    public void update(float dt) {
        if (activeRoute == null || activeRoute.path == null) return;

        switch (state) {
            case MOVE_TO_BASE:
                routeProgress += speed * slowFactor * dt;
                if (routeProgress >= activeRoute.baseDistance) {
                    routeProgress = activeRoute.baseDistance;
                    state = EnemyState.STEAL;
                }
                break;
            case STEAL:
                hasStolen = true;
                // Steal up to orbCapacity or remaining orbs
                int stealCount = Math.min(enemyDef.orbCapacity, TdGameWorld.orbits);
                orbsCarried = stealCount;
                TdGameWorld.orbits -= stealCount;
                TdSaveData.incOrbsLost(stealCount);
                // Switch to a random outbound route
                pickOutboundRoute();
                state = EnemyState.FLEE;
                break;
            case FLEE:
                routeProgress += speed * slowFactor * dt;
                if (routeProgress >= activeRoute.path.getTotalLength()) {
                    reachedEnd = true;
                }
                break;
            case DEAD:
                return;
        }

        if (routeProgress >= activeRoute.path.getTotalLength()) {
            pos = activeRoute.path.sample(activeRoute.path.getTotalLength());
        } else {
            pos = activeRoute.path.sample(routeProgress);
        }
        if (gameObject != null) {
            gameObject.getTransform().setPosition(pos.x, pos.y);
        }

        // Detect segment change and trigger smooth rotation
        int newSegment = activeRoute.path.getSegmentIndex(routeProgress);
        if (newSegment != currentSegment) {
            currentSegment = newSegment;
            triggerSmoothTurn();
        }
    }

    public void pickOutboundRoute() {
        if (TdGameWorld.level == null || TdGameWorld.level.paths == null) return;
        java.util.ArrayList<PathRoute> candidates = new java.util.ArrayList<>();
        for (PathRoute pr : TdGameWorld.level.paths) {
            if (pr.type == RouteType.OUTBOUND) candidates.add(pr);
        }
        if (candidates.isEmpty()) {
            // Fallback: keep using current route if no outbound defined
            return;
        }
        outboundRoute = candidates.get(TdGameWorld.pathRng.nextInt(candidates.size()));
        activeRoute = outboundRoute;
        routeProgress = 0;
        currentSegment = 0;
    }

    public void triggerSmoothTurn() {
        if (gameObject == null) return;
        Vector2 dir = activeRoute.path.direction(routeProgress);
        if (dir == null) return;
        float targetAngle = PApplet.atan2(dir.y, dir.x);
        float currentAngle = gameObject.getTransform().getRotation();
        // Normalize angle difference to [-PI, PI]
        float angleDiff = targetAngle - currentAngle;
        while (angleDiff > PApplet.PI) angleDiff -= PApplet.TWO_PI;
        while (angleDiff < -PApplet.PI) angleDiff += PApplet.TWO_PI;
        float finalTarget = currentAngle + angleDiff;
        // Kill any existing rotation tween on this game object
        TowerDefenseMin2.inst.engine.getTweenManager().killTarget(gameObject);
        TowerDefenseMin2.inst.engine.getTweenManager()
            .toRotation(gameObject, finalTarget, TURN_DURATION)
            .ease(Ease::outQuad)
            .onComplete(() -> isTurning = false)
            .start();
        isTurning = true;
    }
}

/**
 * Orb: energy ball returning to base along its route.
 * Can be re-captured by enemies along the way.
 */
static class Orb {
    Vector2 pos;
    float pathDistance;
    static final float RETURN_SPEED = 80f;
    static final float CAPTURE_RADIUS = 20f;
    GameObject gameObject;
    PathRoute route; // the route this orb is traveling on

    public void update(float dt) {
        if (route == null || route.path == null) return;
        pathDistance -= RETURN_SPEED * dt;
        if (pathDistance < 0) pathDistance = 0;
        pos = route.path.sample(pathDistance);
        if (gameObject != null) {
            gameObject.getTransform().setPosition(pos.x, pos.y);
        }
    }

    public boolean reachedBase() {
        return pathDistance <= route.baseDistance;
    }

    public Enemy findNearbyEnemy() {
        for (Enemy e : TdGameWorld.enemies) {
            if (e.hp <= 0) continue;
            if (e.orbsCarried >= e.enemyDef.orbCapacity) continue;
            float dx = pos.x - e.pos.x;
            float dy = pos.y - e.pos.y;
            if (dx * dx + dy * dy <= CAPTURE_RADIUS * CAPTURE_RADIUS) {
                return e;
            }
        }
        return null;
    }
}

static class OrbRenderer extends RendererComponent {
    Orb orb;
    OrbRenderer(Orb orb) { this.orb = orb; }

    protected void renderShape(PGraphics g) {
        if (orb == null) return;
        float x = orb.pos.x;
        float y = orb.pos.y;
        g.noStroke();
        g.fill(0xFFFFD700, 200);
        g.ellipse(x, y, 10, 10);
        g.fill(0xFFFFFFFF, 120);
        g.ellipse(x, y, 5, 5);
    }
}
