/**
 * Game world state: level data, towers, enemies, bullets, orbs, base/exit state.
 */
static final class TdGameWorld {

    static LevelDef level;
    static int money, orbits, currentWave, escapedEnemies;
    static ArrayList<Tower> towers = new ArrayList<>();
    static ArrayList<Enemy> enemies = new ArrayList<>();
    static ArrayList<Bullet> bullets = new ArrayList<>();
    static ArrayList<Orb> orbs = new ArrayList<>();
    static float waveTimer, spawnTimer;
    static boolean waveInProgress;
    static int waveSpawnIndex;        // current spawn group within wave
    static int waveSpawnCount;        // how many spawned in current group
    static java.util.Random pathRng = new java.util.Random();

    public static void startLevel(TowerDefenseMin2 app, int levelId) {
        // Clean up old entities
        for (Enemy e : enemies) {
            if (e.gameObject != null) e.gameObject.markForDestroy();
        }
        for (Tower t : towers) {
            if (t.gameObject != null) t.gameObject.markForDestroy();
        }
        for (Orb o : orbs) {
            if (o.gameObject != null) o.gameObject.markForDestroy();
        }
        // Recycle all active bullets back to pools
        for (Bullet b : bullets) {
            if (!b.dead) b.recycle();
        }
        towers.clear();
        enemies.clear();
        bullets.clear();
        orbs.clear();

        level = TdAssets.loadLevel(levelId);
        money = level.initialMoney;
        if (level.levelType == LevelType.DEFEND_BASE) {
            orbits = level.baseOrbs;
        } else {
            orbits = 0;
        }
        escapedEnemies = 0;
        currentWave = 0;
        waveSpawnIndex = 0;
        waveSpawnCount = 0;
        waveInProgress = false;
        waveTimer = (level.waves != null && level.waves.length > 0) ? level.waves[0].delay : 9999f;
        spawnTimer = 0;

        // Resize world
        TowerDefenseMin2.WORLD_W = level.worldW;
        TowerDefenseMin2.WORLD_H = level.worldH;
        app.camera.setWorldBounds(new Rect(0, 0, level.worldW, level.worldH));
        if (level.levelType == LevelType.DEFEND_BASE) {
            app.camera.jumpCenterTo(level.basePos.x, level.basePos.y);
        } else {
            app.camera.jumpCenterTo(level.worldW * 0.5f, level.worldH * 0.5f);
        }

        // Preload bullet pools for the new level
        app.bulletDataPool.preload(100);
        app.bulletGoPool.preload(100);
    }

    public static void update(float dt) {
        if (level == null) return;
        int totalWaves = (level.waves != null) ? level.waves.length : 0;

        // Wave management
        if (!waveInProgress && currentWave < totalWaves) {
            waveTimer -= dt;
            if (waveTimer <= 0) {
                currentWave++;
                waveSpawnIndex = 0;
                waveSpawnCount = 0;
                waveInProgress = true;
                spawnTimer = 0;
            }
        }

        // Spawning
        if (waveInProgress && currentWave <= totalWaves && level.waves != null) {
            WaveDef wave = level.waves[currentWave - 1];
            if (waveSpawnIndex < wave.spawns.length) {
                WaveSpawn spawn = wave.spawns[waveSpawnIndex];
                spawnTimer -= dt;
                if (spawnTimer <= 0) {
                    spawnEnemy(spawn.enemyType, spawn.route);
                    waveSpawnCount++;
                    if (waveSpawnCount >= spawn.count) {
                        waveSpawnIndex++;
                        waveSpawnCount = 0;
                        spawnTimer = 0;
                    } else {
                        spawnTimer = spawn.interval;
                    }
                }
            } else {
                waveInProgress = false;
                waveTimer = (currentWave < totalWaves)
                    ? level.waves[currentWave].delay : 9999f;
            }
        }

        // Update orbs
        for (int i = orbs.size() - 1; i >= 0; i--) {
            Orb o = orbs.get(i);
            o.update(dt);
            if (o.reachedBase()) {
                orbits++;
                if (o.gameObject != null) o.gameObject.markForDestroy();
                orbs.remove(i);
                continue;
            }
            Enemy captor = o.findNearbyEnemy();
            if (captor != null) {
                captor.orbsCarried++;
                if (o.gameObject != null) o.gameObject.markForDestroy();
                orbs.remove(i);
            }
        }

        // Update entities
        for (int i = enemies.size() - 1; i >= 0; i--) {
            Enemy e = enemies.get(i);
            e.update(dt);
            if (e.reachedEnd) {
                escapedEnemies++;
                // Orbs carried by escaped enemies are permanently lost in DEFEND_BASE mode
                if (level.levelType == LevelType.DEFEND_BASE && e.orbsCarried > 0) {
                    // orbs already deducted from base when stolen, nothing to do
                }
                if (e.gameObject != null) e.gameObject.markForDestroy();
                enemies.remove(i);
            } else if (e.hp <= 0) {
                e.state = EnemyState.DEAD;
                // Drop carried orbs as returning Orbs
                for (int j = 0; j < e.orbsCarried; j++) {
                    releaseOrb(e.routeProgress, e.activeRoute);
                }
                if (!e.hasStolen && level != null && level.earnMoneyOnKill) {
                    money += TdConfig.KILL_REWARD_BASE;
                }
                TdSaveData.incEnemiesKilled();
                if (e.gameObject != null) e.gameObject.markForDestroy();
                enemies.remove(i);
            }
        }

        for (int i = bullets.size() - 1; i >= 0; i--) {
            Bullet b = bullets.get(i);
            b.update(dt);
            if (b.dead) {
                bullets.remove(i);
            }
        }

        // Tower AI
        for (Tower t : towers) {
            t.update(dt);
        }

        // Check win/lose
        checkWinLose();
    }

    public static void releaseOrb(float atPathDistance, PathRoute route) {
        Orb o = new Orb();
        o.route = route;
        o.pathDistance = atPathDistance;
        o.pos = route != null ? route.path.sample(atPathDistance) : new Vector2();

        GameObject go = GameObject.create("Orb");
        go.getTransform().setPosition(o.pos.x, o.pos.y);
        go.setRenderLayer(12);
        go.addComponent(new OrbRenderer(o));
        TowerDefenseMin2.inst.gameScene.addGameObject(go);
        o.gameObject = go;

        orbs.add(o);
    }

    public static void spawnEnemy(String enemyTypeKey) {
        spawnEnemy(enemyTypeKey, null);
    }

    public static void spawnEnemy(String enemyTypeKey, String routeId) {
        EnemyDef def = TdAssets.loadEnemyDef(enemyTypeKey);
        if (def == null) return;

        PathRoute route = pickSpawnRoute(routeId);
        if (route == null) return;

        Enemy e = new Enemy();
        e.enemyDef = def;
        e.inboundRoute = route;
        e.activeRoute = route;
        e.routeProgress = 0;
        e.pos = route.path.sample(0);
        e.hp = level.enemyHpBase * def.hpMultiplier;
        e.maxHp = e.hp;
        e.speed = def.speedMultiplier * 60; // base speed 60
        e.radius = def.radius;
        e.state = EnemyState.MOVE_TO_BASE;
        e.hasStolen = false;
        e.orbsCarried = 0;

        GameObject go = GameObject.create("Enemy");
        go.getTransform().setPosition(e.pos.x, e.pos.y);
        go.setRenderLayer(10);
        go.addComponent(new EnemyRenderer(e));
        TowerDefenseMin2.inst.gameScene.addGameObject(go);
        e.gameObject = go;

        enemies.add(e);
    }

    public static PathRoute pickSpawnRoute(String routeId) {
        if (level == null || level.paths == null) return null;
        // If routeId specified, find it
        if (routeId != null) {
            for (PathRoute pr : level.paths) {
                if (routeId.equals(pr.id)) return pr;
            }
        }
        // Auto-pick based on level type
        java.util.ArrayList<PathRoute> candidates = new java.util.ArrayList<>();
        for (PathRoute pr : level.paths) {
            if (level.levelType == LevelType.DEFEND_BASE) {
                if (pr.type == RouteType.INBOUND) candidates.add(pr);
            } else {
                if (pr.type == RouteType.DIRECT) candidates.add(pr);
                // Fallback: if no DIRECT, use INBOUND
                if (candidates.isEmpty() && pr.type == RouteType.INBOUND) candidates.add(pr);
            }
        }
        if (candidates.isEmpty()) return null;
        return candidates.get(pathRng.nextInt(candidates.size()));
    }

    public static void checkWinLose() {
        if (level == null) return;
        int totalWaves = (level.waves != null) ? level.waves.length : 0;

        if (level.levelType == LevelType.DEFEND_BASE) {
            // Lose: all orbs have been carried away to the exit by escaped enemies.
            // Base is empty, no orbs returning, and no enemy on the field is still carrying orbs.
            boolean noOrbsLeft = orbits <= 0 && orbs.isEmpty();
            boolean noCarriersOnField = true;
            for (Enemy e : enemies) {
                if (e.orbsCarried > 0) {
                    noCarriersOnField = false;
                    break;
                }
            }
            if (noOrbsLeft && noCarriersOnField) {
                TdFlow.showLose(TowerDefenseMin2.inst);
                return;
            }
            // Win: all waves done, no enemies, and at least one orb in base or returning
            boolean allWavesDone = currentWave >= totalWaves;
            boolean noEnemies = enemies.isEmpty();
            if (allWavesDone && noEnemies && (orbits > 0 || !orbs.isEmpty())) {
                TdFlow.showWin(TowerDefenseMin2.inst);
                return;
            }
        } else {
            // SURVIVAL
            if (escapedEnemies >= level.maxEscapeCount) {
                TdFlow.showLose(TowerDefenseMin2.inst);
                return;
            }
            boolean allWavesDone = currentWave >= totalWaves;
            boolean noEnemies = enemies.isEmpty();
            if (allWavesDone && noEnemies && escapedEnemies < level.maxEscapeCount) {
                TdFlow.showWin(TowerDefenseMin2.inst);
                return;
            }
        }
    }

    public static boolean canPlaceTower(int gx, int gy) {
        if (level == null) return false;
        float wx = (gx + 0.5f) * TdConfig.GRID;
        float wy = (gy + 0.5f) * TdConfig.GRID;
        if (wx < 0 || wy < 0 || wx > level.worldW || wy > level.worldH) return false;
        for (Tower t : towers) {
            if (Math.abs(t.gridX - gx) < 1 && Math.abs(t.gridY - gy) < 1) return false;
        }
        return true;
    }

    public static boolean tryPlaceTower(TdBuildMode mode, int gx, int gy) {
        if (!canPlaceTower(gx, gy)) return false;
        TowerDef def = TdAssets.loadTowerDef(TowerType.fromBuildMode(mode));
        if (def == null || money < def.cost) return false;
        money -= def.cost;
        Tower t = new Tower(def, gx, gy);
        TdSaveData.incTowersBuilt();

        GameObject go = GameObject.create("Tower");
        go.getTransform().setPosition(t.worldX, t.worldY);
        go.setRenderLayer(5);
        go.addComponent(new TowerRenderer(t));
        TowerDefenseMin2.inst.gameScene.addGameObject(go);
        t.gameObject = go;

        towers.add(t);
        TdAssets.playSfx(def.sfxPlace);
        return true;
    }
}
/**
 * Ghost tower preview: managed as a Scene GameObject with RendererComponent.
 * Renders through SceneViewport's off-screen buffer, naturally clipped to world bounds.
 */
static final class TdGhost {

    static int gridX, gridY;
    static boolean isValid;
    static float worldX, worldY;
    static GameObject ghostGo;

    public static void ensureGameObject(TowerDefenseMin2 app) {
        if (ghostGo == null) {
            ghostGo = GameObject.create("ghost_tower");
            ghostGo.setRenderLayer(50);  // above towers(5) and enemies(10)
            ghostGo.addComponent(new GhostRenderer());
            app.gameScene.addGameObject(ghostGo);
        }
    }

    public static void update() {
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        if (app.buildMode == TdBuildMode.NONE || app.camera == null) {
            isValid = false;
            if (ghostGo != null) ghostGo.setActive(false);
            return;
        }
        // Don't show ghost when mouse is over HUD
        if (app.isMouseOverHud()) {
            isValid = false;
            if (ghostGo != null) ghostGo.setActive(false);
            return;
        }
        ensureGameObject(app);
        ghostGo.setActive(true);

        // Coordinate chain: actual mouse \u2192 design coords \u2192 world coords \u2192 snap to grid
        Vector2 dm = app.engine.getDisplayManager().actualToDesign(new Vector2(app.mouseX, app.mouseY));
        Vector2 world = app.camera.screenToWorld(dm);
        gridX = Math.round(world.x / TdConfig.GRID - 0.5f);
        gridY = Math.round(world.y / TdConfig.GRID - 0.5f);
        worldX = (gridX + 0.5f) * TdConfig.GRID;
        worldY = (gridY + 0.5f) * TdConfig.GRID;
        isValid = TdGameWorld.canPlaceTower(gridX, gridY);

        // Sync position to GameObject transform
        ghostGo.getTransform().setPosition(worldX, worldY);
    }

    public static void draw() {
        // Rendering is handled by Scene system via GhostRenderer
    }

    public static void cleanup(TowerDefenseMin2 app) {
        if (ghostGo != null) {
            ghostGo.markForDestroy();
            ghostGo = null;
        }
    }
}

static class GhostRenderer extends RendererComponent {
    @Override
    protected void renderShape(PGraphics g) {
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        if (!TdGhost.isValid || app.buildMode == TdBuildMode.NONE) return;

        float x = getTransform().getPosition().x;
        float y = getTransform().getPosition().y;

        // Tower visual size in world units (matches TowerRenderer)
        float size = TdConfig.GRID * 0.75f;

        // Color by tower type
        int ghostColor;
        switch (app.buildMode) {
            case MG:      ghostColor = 0xFF4A9EFF; break;
            case MISSILE: ghostColor = 0xFFFF643C; break;
            case LASER:   ghostColor = 0xFF3CDC78; break;
            case SLOW:    ghostColor = 0xFFC878DC; break;
            default:      ghostColor = 0xFFFFFFFF;
        }

        // Camera already applies zoom in Scene.renderWorld(), so draw in world units
        float zoom = app.camera.getZoom();
        g.noFill();
        g.stroke(ghostColor);
        g.strokeWeight(2 / zoom);  // counter-scale stroke for consistent screen width
        g.ellipse(x, y, size, size);

        // Range indicator in world units (def.range is world distance)
        TowerDef def = TdAssets.loadTowerDef(TowerType.fromBuildMode(app.buildMode));
        if (def != null) {
            g.strokeWeight(1 / zoom);
            g.stroke(0x55FFFFFF);
            g.noFill();
            g.ellipse(x, y, def.range * 2, def.range * 2);
        }
    }
}
/**
 * HUD elements rendered on screen layer (top bar, right panel, minimap).
 */
static final class TdHUD {

    public static void drawTopBar() {
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        Vector2 d = app.engine.getDisplayManager().actualToDesign(new Vector2(0, 0));
        float x = d.x, y = d.y;
        float w = app.width;
        float h = TdConfig.TOP_HUD;

        app.pushStyle();
        app.noStroke();
        app.fill(TdTheme.BG_TITLE);
        app.rect(x, y, w, h);
        app.stroke(TdTheme.ACCENT);
        app.strokeWeight(1);
        app.noFill();
        app.rect(x + 0.5f, y + 0.5f, w - 1, h - 1);

        app.fill(TdTheme.TEXT);
        app.textAlign(PApplet.LEFT, PApplet.CENTER);
        app.textSize(14);
        String statusText;
        if (TdGameWorld.level != null && TdGameWorld.level.levelType == LevelType.SURVIVAL) {
            statusText = "$ " + TdGameWorld.money + "  \u9003 " + TdGameWorld.escapedEnemies + "/" + TdGameWorld.level.maxEscapeCount
                + "  \u6ce2 " + TdGameWorld.currentWave + "/" + TdGameWorld.level.waves.length;
        } else {
            statusText = "$ " + TdGameWorld.money + "  \u2666 " + TdGameWorld.orbits
                + "  \u6ce2 " + TdGameWorld.currentWave + "/" + (TdGameWorld.level != null ? TdGameWorld.level.waves.length : 0);
        }
        app.text(statusText, x + 16, y + h * 0.5f);

        // Pause button
        float btnW = 72;
        float btnH = 28;
        float btnX = x + w - btnW - 12;
        float btnY = y + (h - btnH) * 0.5f;
        Vector2 dm = app.engine.getDisplayManager().actualToDesign(new Vector2(app.mouseX, app.mouseY));
        boolean pauseHover = dm.x >= btnX && dm.x <= btnX + btnW && dm.y >= btnY && dm.y <= btnY + btnH;
        int pauseFill = pauseHover ? TdTheme.BTN_HOVER : TdTheme.BTN_BG;
        app.noStroke();
        app.fill(pauseFill);
        app.rect(btnX, btnY, btnW, btnH);
        app.stroke(TdTheme.BORDER);
        app.strokeWeight(1);
        app.noFill();
        app.rect(btnX + 0.5f, btnY + 0.5f, btnW - 1, btnH - 1);
        app.fill(TdTheme.TEXT);
        app.textAlign(PApplet.CENTER, PApplet.CENTER);
        app.textSize(12);
        app.text(TdAssets.i18n("game.pause"), btnX + btnW * 0.5f, btnY + btnH * 0.5f);

        app.popStyle();
    }

    public static void drawBuildPanel() {
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        Vector2 d = app.engine.getDisplayManager().actualToDesign(new Vector2(app.width, 0));
        float x = d.x - TdConfig.RIGHT_W;
        float y = TdConfig.TOP_HUD;
        float w = TdConfig.RIGHT_W;
        float h = d.y + app.height - y;

        app.pushStyle();
        app.noStroke();
        app.fill(TdTheme.BG_PANEL);
        app.rect(x, y, w, h);
        app.stroke(TdTheme.BORDER);
        app.strokeWeight(1);
        app.noFill();
        app.rect(x + 0.5f, y + 0.5f, w - 1, h - 1);

        // Tower buttons
        float btnH = 56;
        float gap = 8;
        float by = y + 16;
        TowerType[] types = { TowerType.MG, TowerType.MISSILE, TowerType.LASER, TowerType.SLOW };
        String[] initials = { "M", "R", "L", "S" };
        Vector2 dm = app.engine.getDisplayManager().actualToDesign(new Vector2(app.mouseX, app.mouseY));
        for (int i = 0; i < types.length; i++) {
            TowerType tt = types[i];
            TowerDef def = TdAssets.loadTowerDef(tt);
            if (def == null) continue;
            boolean selected = app.buildMode == TowerType.toBuildMode(tt);
            boolean hover = dm.x >= x + 8 && dm.x <= x + w - 8 && dm.y >= by && dm.y <= by + btnH;
            int fill = selected ? TdTheme.BTN_PRESS : (hover ? TdTheme.BTN_HOVER : TdTheme.BTN_BG);
            app.noStroke();
            app.fill(fill);
            app.rect(x + 8, by, w - 16, btnH);
            app.stroke(selected ? TdTheme.ACCENT : TdTheme.BORDER);
            app.strokeWeight(selected ? 2 : 1);
            app.noFill();
            app.rect(x + 8.5f, by + 0.5f, w - 17, btnH - 1);

            // Icon
            float iconSize = 32;
            float iconX = x + 16;
            float iconY = by + (btnH - iconSize) * 0.5f;
            app.noStroke();
            app.fill(TdConfig.C_ACCENT);
            app.rect(iconX, iconY, iconSize, iconSize);
            app.fill(TdTheme.BG_DARK);
            app.textAlign(PApplet.CENTER, PApplet.CENTER);
            app.textSize(14);
            app.text(initials[i], iconX + iconSize * 0.5f, iconY + iconSize * 0.5f);

            // Name and cost
            app.fill(TdTheme.TEXT);
            app.textAlign(PApplet.LEFT, PApplet.CENTER);
            app.textSize(13);
            app.text(TdAssets.i18n(def.nameKey), iconX + iconSize + 10, by + btnH * 0.35f);
            app.fill(TdTheme.TEXT_DIM);
            app.textSize(11);
            app.text("$" + def.cost, iconX + iconSize + 10, by + btnH * 0.7f);

            by += btnH + gap;
        }

        // Cancel button
        by += 8;
        float cancelH = 32;
        boolean cancelHover = dm.x >= x + 8 && dm.x <= x + w - 8 && dm.y >= by && dm.y <= by + cancelH;
        int cancelFill = cancelHover ? TdTheme.BTN_HOVER : TdTheme.BTN_BG;
        app.noStroke();
        app.fill(cancelFill);
        app.rect(x + 8, by, w - 16, cancelH);
        app.stroke(TdTheme.BORDER);
        app.strokeWeight(1);
        app.noFill();
        app.rect(x + 8.5f, by + 0.5f, w - 17, cancelH - 1);
        app.fill(TdTheme.TEXT);
        app.textAlign(PApplet.CENTER, PApplet.CENTER);
        app.textSize(12);
        app.text(TdAssets.i18n("game.build.cancel"), x + w * 0.5f, by + cancelH * 0.5f);

        app.popStyle();
    }

    public static void drawMinimap() {
        TdMinimap.draw();
    }

    public static void handleMinimapClick() {
        TdMinimap.handleClick();
    }

    public static void drawPauseOverlay() {
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        app.pushStyle();
        app.fill(0x66000000);
        app.noStroke();
        app.rect(0, 0, app.width, app.height);
        app.fill(TdTheme.TEXT);
        app.textAlign(PApplet.CENTER, PApplet.CENTER);
        app.textSize(32);
        app.text("PAUSED", app.width * 0.5f, app.height * 0.5f);
        app.popStyle();
    }

    public static boolean isPauseButtonHit(float mx, float my) {
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        Vector2 d = app.engine.getDisplayManager().actualToDesign(new Vector2(0, 0));
        float x = d.x, y = d.y;
        float w = app.width;
        float h = TdConfig.TOP_HUD;
        float btnW = 72;
        float btnH = 28;
        float btnX = x + w - btnW - 12;
        float btnY = y + (h - btnH) * 0.5f;
        return mx >= btnX && mx <= btnX + btnW && my >= btnY && my <= btnY + btnH;
    }

    public static TdBuildMode getBuildModeAt(float mx, float my) {
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        Vector2 d = app.engine.getDisplayManager().actualToDesign(new Vector2(app.width, 0));
        float x = d.x - TdConfig.RIGHT_W;
        float y = TdConfig.TOP_HUD;
        float w = TdConfig.RIGHT_W;
        float btnH = 56;
        float gap = 8;
        float by = y + 16;
        TowerType[] allTypes = { TowerType.MG, TowerType.MISSILE, TowerType.LASER, TowerType.SLOW };
        TowerType[] allowed = (TdGameWorld.level != null && TdGameWorld.level.allowedTowers != null)
            ? TdGameWorld.level.allowedTowers : allTypes;
        for (int i = 0; i < allTypes.length; i++) {
            TowerType tt = allTypes[i];
            boolean isAllowed = false;
            for (TowerType a : allowed) {
                if (a == tt) { isAllowed = true; break; }
            }
            if (!isAllowed) continue;
            TowerDef def = TdAssets.loadTowerDef(tt);
            if (def == null) continue;
            if (mx >= x + 8 && mx <= x + w - 8 && my >= by && my <= by + btnH) {
                return TowerType.toBuildMode(tt);
            }
            by += btnH + gap;
        }
        // Cancel button
        by += 8;
        float cancelH = 32;
        if (mx >= x + 8 && mx <= x + w - 8 && my >= by && my <= by + cancelH) {
            return TdBuildMode.NONE;
        }
        return null;
    }
}
/**
 * Level data loader placeholder.
 * Actual loading implemented in TdAssets (YAML via snakeyaml).
 */
/**
 * Map renderer: draws grid, path, base, spawn point in world space.
 */
static final class TdMap {

    public static void render() {
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        LevelDef lv = TdGameWorld.level;
        if (lv == null) return;

        app.pushStyle();

        // Grid
        app.stroke(TdTheme.BORDER);
        app.strokeWeight(1);
        app.noFill();
        for (int gx = 0; gx <= lv.worldW; gx += TdConfig.GRID) {
            app.line(gx, 0, gx, lv.worldH);
        }
        for (int gy = 0; gy <= lv.worldH; gy += TdConfig.GRID) {
            app.line(0, gy, lv.worldW, gy);
        }

        // Path
        if (lv.pathPoints.length > 1) {
            app.stroke(0xFF4A9EFF);
            app.strokeWeight(12);
            app.strokeCap(PApplet.ROUND);
            for (int i = 1; i < lv.pathPoints.length; i++) {
                app.line(lv.pathPoints[i-1].x, lv.pathPoints[i-1].y, lv.pathPoints[i].x, lv.pathPoints[i].y);
            }
        }

        // Base
        app.noStroke();
        app.fill(0xFF4A9EFF);
        app.ellipse(lv.basePos.x, lv.basePos.y, 24, 24);
        app.fill(TdTheme.TEXT);
        app.textAlign(PApplet.CENTER, PApplet.CENTER);
        app.textSize(10);
        app.text("BASE", lv.basePos.x, lv.basePos.y);

        // Exit
        app.noStroke();
        app.fill(0xFFFF4444);
        app.ellipse(lv.exitPos.x, lv.exitPos.y, 16, 16);

        // Spawn
        app.noStroke();
        app.fill(0xFFFF8C42);
        app.ellipse(lv.spawnPos.x, lv.spawnPos.y, 12, 12);

        app.popStyle();
    }
}
/**
 * Animated sci-fi menu background with stars and grid lines.
 */
static final class TdMenuBg {

    static class Star {
        float x, y, z, brightness;
        Star(float x, float y, float z, float b) { this.x = x; this.y = y; this.z = z; this.brightness = b; }
    }

    static final int STAR_COUNT = 200;
    static final ArrayList<Star> stars = new ArrayList<>();
    static float time = 0;
    static boolean initialized = false;
    static processing.core.PFont font;

    // Title animation state (0 = start, 1 = end)
    static float titleProgress = 0f;

    public static void setFont(processing.core.PFont f) {
        font = f;
    }

    public static void init() {
        if (initialized) return;
        java.util.Random rng = new java.util.Random(42);
        for (int i = 0; i < STAR_COUNT; i++) {
            stars.add(new Star(
                rng.nextFloat() * 1280,
                rng.nextFloat() * 720,
                rng.nextFloat() * 2 + 0.5f,
                rng.nextFloat() * 200 + 55
            ));
        }
        initialized = true;
    }

    public static void update(float dt) {
        time += dt;
    }

    public static void drawTitle(PApplet g, String title) {
        // Animated position: center (360) -> final (120)
        float startY = 360f;
        float endY = 120f;
        float curY = startY + (endY - startY) * titleProgress;

        // Animated alpha: 0 -> 255
        int alpha = (int)(Math.min(255, Math.max(0, 255 * titleProgress)));

        // Animated scale: 0.8 -> 1.0
        float scale = Math.max(0, 0.8f + 0.2f * titleProgress);

        g.textAlign(PApplet.CENTER, PApplet.CENTER);
        if (font != null) g.textFont(font);
        g.textSize(48 * scale);

        float tw = g.textWidth(title);

        // Glow shadow
        g.fill(74, 158, 255, (int)(60 * titleProgress));
        g.text(title, 642, curY + 2);
        g.text(title, 638, curY - 2);
        // Main text
        g.fill(224, 230, 240, alpha);
        g.text(title, 640, curY);
        // Accent underline
        g.stroke(74, 158, 255, (int)(180 * titleProgress));
        g.strokeWeight(2);
        g.line(640 - tw * 0.5f, curY + 32, 640 + tw * 0.5f, curY + 32);
    }

    public static void draw(PApplet g) {
        init();

        // Deep space background
        g.background(14, 18, 34);

        // Draw stars with twinkle
        g.noStroke();
        for (Star s : stars) {
            float twinkle = 0.7f + 0.3f * PApplet.sin(time * s.z + s.x * 0.01f);
            int alpha = (int)(s.brightness * twinkle);
            g.fill(200, 220, 255, alpha);
            float sz = 1 + s.z * 0.8f;
            g.ellipse(s.x, s.y, sz, sz);
        }

        // Subtle perspective grid
        g.stroke(40, 60, 100, 40);
        g.strokeWeight(1);
        float horizonY = 400;
        // Horizontal lines
        for (int i = 0; i < 12; i++) {
            float y = horizonY + i * 35;
            if (y > 720) break;
            float alpha = PApplet.map(y, horizonY, 720, 30, 80);
            g.stroke(40, 60, 100, (int)alpha);
            g.line(0, y, 1280, y);
        }
        // Vertical perspective lines
        float cx = 640;
        for (int i = -8; i <= 8; i++) {
            float x2 = cx + i * 120;
            g.stroke(40, 60, 100, 25);
            g.line(cx, horizonY - 100, x2, 720);
        }

        // Subtle vignette (darken edges)
        g.noStroke();
        for (int i = 0; i < 3; i++) {
            float t = i / 3f;
            int a = (int)(40 * (1 - t));
            g.fill(0, 0, 0, a);
            float margin = t * 200;
            g.rect(0, 0, 1280, margin);
            g.rect(0, 720 - margin, 1280, margin);
            g.rect(0, 0, margin, 720);
            g.rect(1280 - margin, 0, margin, 720);
        }
    }
}
/**
 * Minimap widget \u2014 encapsulates bounds, drawing, and click-to-jump logic.
 */
static final class TdMinimap {
    static final float MW = 180, MH = 120;

    public static float getX() {
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        Vector2 d = app.engine.getDisplayManager().actualToDesign(new Vector2(app.width, app.height));
        return d.x - TdConfig.RIGHT_W + 16;
    }

    public static float getY() {
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        Vector2 d = app.engine.getDisplayManager().actualToDesign(new Vector2(app.width, app.height));
        return d.y - MH - 16;
    }

    public static boolean isMouseOver() {
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        Vector2 dm = app.engine.getDisplayManager().actualToDesign(new Vector2(app.mouseX, app.mouseY));
        float mx = getX();
        float my = getY();
        return dm.x >= mx && dm.x <= mx + MW && dm.y >= my && dm.y <= my + MH;
    }

    public static void handleClick() {
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        if (TdGameWorld.level == null || app.camera == null) return;
        Vector2 dm = app.engine.getDisplayManager().actualToDesign(new Vector2(app.mouseX, app.mouseY));
        float mx = getX();
        float my = getY();
        float wx = (dm.x - mx) / MW * TdGameWorld.level.worldW;
        float wy = (dm.y - my) / MH * TdGameWorld.level.worldH;
        app.camera.jumpCenterTo(wx, wy);
    }

    public static void draw() {
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        float mx = getX();
        float my = getY();

        app.pushStyle();
        app.noStroke();
        app.fill(TdTheme.BG_DARK);
        app.rect(mx, my, MW, MH);
        app.stroke(TdTheme.BORDER);
        app.strokeWeight(1);
        app.noFill();
        app.rect(mx + 0.5f, my + 0.5f, MW - 1, MH - 1);

        if (TdGameWorld.level != null) {
            float sx = MW / TdGameWorld.level.worldW;
            float sy = MH / TdGameWorld.level.worldH;
            // Base
            app.fill(0xFF4A9EFF);
            app.ellipse(mx + TdGameWorld.level.basePos.x * sx, my + TdGameWorld.level.basePos.y * sy, 6, 6);
            // Exit
            app.fill(0xFFFF4444);
            app.ellipse(mx + TdGameWorld.level.exitPos.x * sx, my + TdGameWorld.level.exitPos.y * sy, 6, 6);
            // Path
            app.stroke(0xFF4A9EFF);
            app.strokeWeight(1);
            Vector2[] pts = TdGameWorld.level.pathPoints;
            for (int i = 1; i < pts.length; i++) {
                app.line(mx + pts[i-1].x * sx, my + pts[i-1].y * sy,
                         mx + pts[i].x * sx, my + pts[i].y * sy);
            }
            // Towers (fixed screen-pixel size so they remain visible)
            app.noStroke();
            app.fill(0xFF66FF66);
            for (Tower t : TdGameWorld.towers) {
              app.rect(mx + t.worldX * sx - 4, my + t.worldY * sy - 4, 6, 6);
            }
            // Orbs
            app.noStroke();
            app.fill(0xFFFFD700);
            for (Orb o : TdGameWorld.orbs) {
              app.ellipse(mx + o.pos.x * sx, my + o.pos.y * sy, 4, 4);
            }

            // Enemies
            app.noStroke();
            app.fill(0xFFFF4444);
            for (Enemy e : TdGameWorld.enemies) {
              app.ellipse(mx + e.pos.x * sx, my + e.pos.y * sy, 5, 5);
            }

            // Camera rect
            Camera2D cam = app.camera;
            float cx = cam.getTransform().getPosition().x;
            float cy = cam.getTransform().getPosition().y;
            float cw = cam.getViewportWidth() / cam.getZoom();
            float ch = cam.getViewportHeight() / cam.getZoom();
            app.noFill();
            app.stroke(0xFFFF8C42);
            app.strokeWeight(1);
            app.rect(mx + (cx - cw * 0.5f) * sx, my + (cy - ch * 0.5f) * sy, cw * sx, ch * sy);
        }

        app.popStyle();
    }
}
/**
 * Path system: polyline with distance sampling for enemy movement.
 */
static final class TdPath {
    public Vector2[] points;
    public float[] segmentLengths;
    public float totalLength;

    TdPath(Vector2[] points) {
        this.points = points;
        computeLengths();
    }

    private void computeLengths() {
        if (points == null || points.length < 2) {
            segmentLengths = new float[0];
            totalLength = 0;
            return;
        }
        segmentLengths = new float[points.length - 1];
        totalLength = 0;
        for (int i = 0; i < points.length - 1; i++) {
            float len = points[i].distance(points[i + 1]);
            segmentLengths[i] = len;
            totalLength += len;
        }
    }

    /** Sample position at distance along the path. */
    public Vector2 sample(float dist) {
        if (points == null || points.length == 0) return new Vector2();
        if (dist <= 0) return points[0].copy();
        if (dist >= totalLength) return points[points.length - 1].copy();
        float accumulated = 0;
        for (int i = 0; i < segmentLengths.length; i++) {
            if (accumulated + segmentLengths[i] >= dist) {
                float t = (dist - accumulated) / segmentLengths[i];
                return Vector2.lerp(points[i], points[i + 1], t);
            }
            accumulated += segmentLengths[i];
        }
        return points[points.length - 1].copy();
    }

    /** Get direction vector at distance along the path. */
    public Vector2 direction(float dist) {
        if (points == null || points.length < 2) return new Vector2(1, 0);
        if (dist <= 0) return points[1].copy().sub(points[0]).normalize();
        if (dist >= totalLength) {
            return points[points.length - 1].copy().sub(points[points.length - 2]).normalize();
        }
        float accumulated = 0;
        for (int i = 0; i < segmentLengths.length; i++) {
            if (accumulated + segmentLengths[i] >= dist) {
                return points[i + 1].copy().sub(points[i]).normalize();
            }
            accumulated += segmentLengths[i];
        }
        return points[points.length - 1].copy().sub(points[points.length - 2]).normalize();
    }

    /** Find the distance along the path closest to the given point. */
    public float closestDistanceTo(Vector2 target) {
        if (points == null || points.length == 0) return 0;
        float bestDist = 0;
        float bestD = Float.MAX_VALUE;
        float accumulated = 0;
        for (int i = 0; i < segmentLengths.length; i++) {
            Vector2 a = points[i];
            Vector2 b = points[i + 1];
            Vector2 ab = b.copy().sub(a);
            Vector2 at = target.copy().sub(a);
            float abLenSq = ab.x * ab.x + ab.y * ab.y;
            float t = abLenSq > 0 ? PApplet.constrain((at.x * ab.x + at.y * ab.y) / abLenSq, 0, 1) : 0;
            Vector2 closest = Vector2.lerp(a, b, t);
            float d = closest.distance(target);
            if (d < bestD) {
                bestD = d;
                bestDist = accumulated + segmentLengths[i] * t;
            }
            accumulated += segmentLengths[i];
        }
        return bestDist;
    }

    /** Get the segment index at the given distance along the path. */
    public int getSegmentIndex(float dist) {
        if (points == null || points.length < 2) return 0;
        if (dist <= 0) return 0;
        if (dist >= totalLength) return segmentLengths.length - 1;
        float accumulated = 0;
        for (int i = 0; i < segmentLengths.length; i++) {
            if (accumulated + segmentLengths[i] >= dist) {
                return i;
            }
            accumulated += segmentLengths[i];
        }
        return segmentLengths.length - 1;
    }

    public float getTotalLength() { return totalLength; }
}
/**
 * Render Components for world layer (renderLayer < 100).
 * Drawn inside SceneViewport's off-screen buffer via p5engine renderer.
 */

static class WorldBgRenderer extends RendererComponent {
    protected void renderShape(PGraphics g) {
        LevelDef lv = TdGameWorld.level;
        if (lv == null) return;

        // Grid
        g.stroke(TdTheme.BORDER);
        g.strokeWeight(1);
        g.noFill();
        for (int gx = 0; gx <= lv.worldW; gx += TdConfig.GRID) {
            g.line(gx, 0, gx, lv.worldH);
        }
        for (int gy = 0; gy <= lv.worldH; gy += TdConfig.GRID) {
            g.line(0, gy, lv.worldW, gy);
        }

        // Path with glow \u2014 draw all routes (new multi-path format) or legacy pathPoints
        float t = (System.currentTimeMillis() % 2000) / 2000f;
        Vector2[][] routesToDraw = null;
        if (lv.paths != null && lv.paths.length > 0) {
            routesToDraw = new Vector2[lv.paths.length][];
            for (int r = 0; r < lv.paths.length; r++) {
                routesToDraw[r] = lv.paths[r].path.points;
            }
        } else if (lv.pathPoints != null && lv.pathPoints.length > 1) {
            routesToDraw = new Vector2[][]{ lv.pathPoints };
        }
        if (routesToDraw != null) {
            for (Vector2[] pts : routesToDraw) {
                if (pts == null || pts.length < 2) continue;
                // Outer glow
                g.stroke(0xFF4A9EFF);
                g.strokeWeight(18);
                g.strokeCap(PApplet.ROUND);
                g.strokeJoin(PApplet.ROUND);
                for (int i = 1; i < pts.length; i++) {
                    g.line(pts[i-1].x, pts[i-1].y, pts[i].x, pts[i].y);
                }
                // Inner core
                g.stroke(0xFF88CCFF);
                g.strokeWeight(8);
                for (int i = 1; i < pts.length; i++) {
                    g.line(pts[i-1].x, pts[i-1].y, pts[i].x, pts[i].y);
                }
                // Animated dash
                g.stroke(0xFFFFFFFF);
                g.strokeWeight(3);
                float dashLen = 40;
                float gapLen = 60;
                float cycle = dashLen + gapLen;
                float offset = t * cycle;
                for (int i = 1; i < pts.length; i++) {
                    Vector2 a = pts[i-1];
                    Vector2 b = pts[i];
                    float segLen = PApplet.dist(a.x, a.y, b.x, b.y);
                    if (segLen <= 0) continue;
                    float rdx = (a.x - b.x) / segLen;
                    float rdy = (a.y - b.y) / segLen;
                    float drawn = -offset;
                    while (drawn < segLen) {
                        float start = PApplet.max(0, drawn);
                        float end = PApplet.min(segLen, drawn + dashLen);
                        if (end > start) {
                            g.line(b.x + rdx * start, b.y + rdy * start,
                                   b.x + rdx * end, b.y + rdy * end);
                        }
                        drawn += cycle;
                    }
                }
            }
        }

        // Base \u2014 pulsing blue core with rotating ring
        float time = System.currentTimeMillis() / 1000f;
        float pulse = 1 + 0.15f * PApplet.sin(time * 3);
        g.noStroke();
        // Outer glow
        g.fill(0xFF4A9EFF, 60);
        g.ellipse(lv.basePos.x, lv.basePos.y, 48 * pulse, 48 * pulse);
        // Core
        g.fill(0xFF4A9EFF);
        g.ellipse(lv.basePos.x, lv.basePos.y, 20, 20);
        g.fill(0xFFFFFFFF);
        g.ellipse(lv.basePos.x, lv.basePos.y, 8, 8);
        // Rotating ring
        g.noFill();
        g.stroke(0xFF88CCFF, 180);
        g.strokeWeight(2);
        g.pushMatrix();
        g.translate(lv.basePos.x, lv.basePos.y);
        g.rotate(time * 1.5f);
        g.arc(0, 0, 36, 36, 0, PApplet.PI * 1.3f);
        g.popMatrix();

        // Exit \u2014 red X mark
        g.noStroke();
        g.fill(0xFFFF4444, 80);
        g.ellipse(lv.exitPos.x, lv.exitPos.y, 28, 28);
        g.stroke(0xFFFF4444);
        g.strokeWeight(3);
        float ex = 6;
        g.line(lv.exitPos.x - ex, lv.exitPos.y - ex, lv.exitPos.x + ex, lv.exitPos.y + ex);
        g.line(lv.exitPos.x + ex, lv.exitPos.y - ex, lv.exitPos.x - ex, lv.exitPos.y + ex);

        // Spawn \u2014 orange pulsing dot
        float sp = 1 + 0.2f * PApplet.sin(time * 4);
        g.noStroke();
        g.fill(0xFFFF8C42, 100);
        g.ellipse(lv.spawnPos.x, lv.spawnPos.y, 20 * sp, 20 * sp);
        g.fill(0xFFFF8C42);
        g.ellipse(lv.spawnPos.x, lv.spawnPos.y, 10, 10);
    }
}

static class EnemyRenderer extends RendererComponent {
    Enemy enemy;
    EnemyRenderer(Enemy enemy) { this.enemy = enemy; }

    protected void renderShape(PGraphics g) {
        if (enemy == null || enemy.hp <= 0) return;

        float x = enemy.pos.x;
        float y = enemy.pos.y;
        float r = enemy.radius;
        float dir = 0;
        if (enemy.gameObject != null) {
            dir = enemy.gameObject.getTransform().getRotation();
        } else if (enemy.activeRoute != null && enemy.activeRoute.path != null) {
            Vector2 d = enemy.activeRoute.path.direction(enemy.routeProgress);
            if (d != null) dir = PApplet.atan2(d.y, d.x);
        }

        g.pushMatrix();
        g.translate(x, y);
        g.rotate(dir);

        // Glow \u2014 red by default, gold when carrying orbs
        g.noStroke();
        if (enemy.orbsCarried > 0) {
            g.fill(0xFFFFDD00, 80);
        } else {
            g.fill(0xFFFF4444, 60);
        }
        g.ellipse(0, 0, r * 2.8f, r * 2.8f);

        // Body \u2014 red by default, gold only when carrying orbs
        int bodyColor = enemy.orbsCarried > 0 ? 0xFFFFDD00 : 0xFFFF6666;
        g.fill(bodyColor);
        g.beginShape();
        g.vertex(r * 1.2f, 0);
        g.vertex(-r * 0.6f, -r * 0.7f);
        g.vertex(-r * 0.3f, 0);
        g.vertex(-r * 0.6f, r * 0.7f);
        g.endShape(PApplet.CLOSE);

        // Orb capacity indicator \u2014 small dots behind body
        if (enemy.enemyDef != null && enemy.enemyDef.orbCapacity > 1) {
            g.noStroke();
            g.fill(0xFFFFD700, 180);
            float dotR = 2.5f;
            float spacing = 7f;
            float startY = -(enemy.enemyDef.orbCapacity - 1) * spacing * 0.5f;
            for (int i = 0; i < enemy.enemyDef.orbCapacity; i++) {
                int dotColor = (i < enemy.orbsCarried) ? 0xFFFFD700 : 0xFF888888;
                g.fill(dotColor, 200);
                g.ellipse(-r * 0.8f, startY + i * spacing, dotR * 2, dotR * 2);
            }
        }

        g.popMatrix();

        // HP bar (screen-aligned)
        float barW = r * 2.4f;
        float barH = 5;
        float barX = x - barW * 0.5f;
        float barY = y - r - 12;
        g.noStroke();
        g.fill(0xFF222222, 200);
        g.rect(barX - 1, barY - 1, barW + 2, barH + 2, 2);
        g.fill(0xFF333333);
        g.rect(barX, barY, barW, barH, 2);
        float hpPct = enemy.maxHp > 0 ? enemy.hp / enemy.maxHp : 0;
        int hpColor = hpPct > 0.5f ? 0xFF44FF66 : (hpPct > 0.25f ? 0xFFFFCC44 : 0xFFFF4444);
        g.fill(hpColor);
        g.rect(barX, barY, barW * hpPct, barH, 2);
    }
}

static class TowerRenderer extends RendererComponent {
    Tower tower;
    TowerRenderer(Tower tower) { this.tower = tower; }

    protected void renderShape(PGraphics g) {
        if (tower == null) return;
        float size = TdConfig.GRID * 0.75f;
        float half = size * 0.5f;
        float x = tower.worldX;
        float y = tower.worldY;
        int c = tower.def.iconColor;
        float time = System.currentTimeMillis() / 1000f;

        // Range indicator (shown when building or manually toggled)
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        boolean shouldShowRange = app.showTowerRanges || app.buildMode != TdBuildMode.NONE;
        if (tower.built && shouldShowRange) {
            g.noFill();
            g.stroke(c & 0x40FFFFFF);
            g.strokeWeight(1);
            g.ellipse(x, y, tower.def.range * 2, tower.def.range * 2);
        }

        // Build animation
        if (!tower.built) {
            float prog = tower.buildProgress / tower.def.buildTime;
            float pulse = 1 + 0.15f * PApplet.sin(time * 8);
            g.noStroke();
            g.fill(0xFF444444, 180);
            g.rect(x - half, y - half, size, size, 4);
            g.fill(c, 120);
            g.rect(x - half, y - half, size * prog, size, 4);
            // Building pulse
            g.noFill();
            g.stroke(c, 150);
            g.strokeWeight(2);
            g.rect(x - half * pulse, y - half * pulse, size * pulse, size * pulse, 4);
            return;
        }

        // Tower shadow
        g.noStroke();
        g.fill(0xFF000000, 60);
        g.rect(x - half + 3, y - half + 3, size, size, 4);

        // Tower body by type
        g.noStroke();
        g.fill(c);
        switch (tower.def.type) {
            case MG:
                g.rect(x - half, y - half, size, size, 3);
                g.fill(0xFFFFFFFF, 120);
                g.rect(x - half + 4, y - half + 4, size - 8, 4, 1);
                break;
            case MISSILE:
                g.ellipse(x, y, size, size);
                g.fill(0xFFFFFFFF, 120);
                g.ellipse(x, y, size * 0.4f, size * 0.4f);
                break;
            case LASER:
                g.pushMatrix();
                g.translate(x, y);
                g.rotate(PApplet.PI / 4);
                g.rect(-half, -half, size, size, 3);
                g.popMatrix();
                g.fill(0xFFFFFFFF, 120);
                g.ellipse(x, y, size * 0.3f, size * 0.3f);
                break;
            case SLOW:
                drawHexagon(g, x, y, half * 0.9f);
                g.fill(0xFFFFFFFF, 120);
                g.ellipse(x, y, size * 0.35f, size * 0.35f);
                break;
        }
    }

    private void drawHexagon(PGraphics g, float cx, float cy, float r) {
        g.beginShape();
        for (int i = 0; i < 6; i++) {
            float a = PApplet.TWO_PI / 6 * i - PApplet.PI / 2;
            g.vertex(cx + PApplet.cos(a) * r, cy + PApplet.sin(a) * r);
        }
        g.endShape(PApplet.CLOSE);
    }
}

static class BulletRenderer extends RendererComponent {
    Bullet bullet;  // dynamically bound by Tower.fireAt()

    protected void renderShape(PGraphics g) {
        if (bullet == null || bullet.dead) return;

        float x = bullet.pos.x;
        float y = bullet.pos.y;

        // Trail
        g.noStroke();
        g.fill(0xFFFFFF00, 60);
        g.ellipse(x - bullet.vel.x * 0.02f, y - bullet.vel.y * 0.02f, 5, 5);
        g.fill(0xFFFFFF00, 120);
        g.ellipse(x - bullet.vel.x * 0.01f, y - bullet.vel.y * 0.01f, 3, 3);

        // Core
        g.fill(0xFFFFFFFF);
        g.ellipse(x, y, 4, 4);
    }
}
/**
 * Persistent save data using p5engine SketchConfig.
 * Stored in TowerDefenseMin2.ini under [stats] and [camera] sections.
 */
static final class TdSaveData {

    static shenyf.p5engine.config.SketchConfig cfg;

    public static void load(PApplet app) {
        String path = app.sketchPath("TowerDefenseMin2.ini");
        java.io.File f = new java.io.File(path);
        boolean firstRun = !f.exists();
        if (firstRun) {
            try { f.createNewFile(); } catch (Exception e) {}
        }
        cfg = new shenyf.p5engine.config.SketchConfig(path);

        if (firstRun) {
            // Initialize all defaults on first launch
            cfg.set("stats", "gamesPlayed", 0);
            cfg.set("stats", "towersBuilt", 0);
            cfg.set("stats", "enemiesKilled", 0);
            cfg.set("stats", "gamesLost", 0);
            cfg.set("stats", "orbsLost", 0);
            cfg.set("audio", "masterVolume", "1.0");
            cfg.set("audio", "bgmVolume", "1.0");
            cfg.set("audio", "sfxVolume", "1.0");
            cfg.set("ui", "language", "zh");
            cfg.set("camera", "zoomAtMouse", false);
            cfg.save();
        }
    }

    public static void save() {
        if (cfg != null) cfg.save();
    }

    // \u2500\u2500 Stats \u2500\u2500

    public static int gamesPlayed()   { return cfg.getInt("stats", "gamesPlayed", 0); }
    public static int towersBuilt()   { return cfg.getInt("stats", "towersBuilt", 0); }
    public static int enemiesKilled() { return cfg.getInt("stats", "enemiesKilled", 0); }
    public static int gamesLost()     { return cfg.getInt("stats", "gamesLost", 0); }
    public static int orbsLost()      { return cfg.getInt("stats", "orbsLost", 0); }

    public static void incGamesPlayed()   { cfg.set("stats", "gamesPlayed", gamesPlayed() + 1); }
    public static void incTowersBuilt()   { cfg.set("stats", "towersBuilt", towersBuilt() + 1); }
    public static void incEnemiesKilled() { cfg.set("stats", "enemiesKilled", enemiesKilled() + 1); }
    public static void incGamesLost()     { cfg.set("stats", "gamesLost", gamesLost() + 1); }
    public static void incOrbsLost(int count) { cfg.set("stats", "orbsLost", orbsLost() + count); }

    // \u2500\u2500 Settings (not auto-saved; call saveSettings() manually) \u2500\u2500

    public static boolean isZoomAtMouse() {
        return cfg.getBoolean("camera", "zoomAtMouse", false);
    }

    public static void setZoomAtMouse(boolean v) {
        cfg.set("camera", "zoomAtMouse", v);
    }

    public static float getMasterVolume() { return parseFloat(cfg.get("audio", "masterVolume", "1.0")); }
    public static float getBgmVolume()    { return parseFloat(cfg.get("audio", "bgmVolume", "1.0")); }
    public static float getSfxVolume()    { return parseFloat(cfg.get("audio", "sfxVolume", "1.0")); }
    public static String getLanguage()    { return cfg.get("ui", "language", "zh"); }

    public static void setMasterVolume(float v) { cfg.set("audio", "masterVolume", String.valueOf(v)); }
    public static void setBgmVolume(float v)    { cfg.set("audio", "bgmVolume", String.valueOf(v)); }
    public static void setSfxVolume(float v)    { cfg.set("audio", "sfxVolume", String.valueOf(v)); }
    public static void setLanguage(String v)    { cfg.set("ui", "language", v); }

    public static void saveSettings() {
        if (cfg != null) cfg.save();
    }
}
/**
 * Sound & BGM manager (Observer pattern).
 * Only one BGM stream plays at a time. Playlist advances via onComplete callback.
 */
static final class TdSound {

    static final String SFX_CLICK = "sounds/synthetic-select.wav";
    static final String SFX_SHOT  = "sounds/synthetic-spike.wav";
    static final String SFX_LASER = "sounds/resonant-twang.wav";
    static final String SFX_PLACE = "sounds/percussive-knock.wav";
    static final String SFX_TOWER_SELECT = "sounds/keypunch.wav";
    static final String BGM_MENU  = "music/TopGun.ogg";

    static TinyMusicClip currentBgm = null;
    static String currentBgmPath = null;
    static String[] gameTracks = null;
    static int currentTrackIndex = -1;

    /** Scan music/ folder for Track*.ogg files (call once in setup). */
    public static void initTracks(PApplet app) {
        if (gameTracks != null) return;
        java.io.File dir = new java.io.File(app.sketchPath("music"));
        java.util.ArrayList<String> list = new java.util.ArrayList<>();
        if (dir.exists() && dir.isDirectory()) {
            java.io.File[] files = dir.listFiles();
            if (files != null) {
                for (java.io.File f : files) {
                    String name = f.getName();
                    if (name.startsWith("Track") && name.endsWith(".ogg")) {
                        list.add("music/" + name);
                    }
                }
            }
        }
        java.util.Collections.sort(list);
        gameTracks = list.toArray(new String[0]);
    }

    /** Stop and unload current BGM. */
    public static void stopBgm() {
        if (currentBgm != null) {
            P5Engine.getInstance().getAudio().unregisterMusic(currentBgm);
            currentBgm.stop();
            currentBgm.unload();
            currentBgm = null;
        }
        currentBgmPath = null;
    }

    /** Menu BGM: TopGun.ogg, loop forever. */
    public static void playBgmMenu() {
        if (BGM_MENU.equals(currentBgmPath) && currentBgm != null && currentBgm.isPlaying()) {
            return; // already playing menu BGM
        }
        stopBgm();
        currentBgmPath = BGM_MENU;
        currentBgm = P5Engine.getInstance().getAudio().loadMusic(BGM_MENU);
        if (currentBgm != null) {
            currentBgm.loop();
        }
    }

    /** Game BGM: pick a random Track*.ogg, auto-advance on completion. */
    public static void playBgmGame() {
        stopBgm();
        if (gameTracks == null || gameTracks.length == 0) return;
        currentTrackIndex = (int)(Math.random() * gameTracks.length);
        playTrack(currentTrackIndex);
    }

    public static void playTrack(int index) {
        if (gameTracks == null || gameTracks.length == 0) return;
        currentTrackIndex = index % gameTracks.length;
        currentBgmPath = gameTracks[currentTrackIndex];
        currentBgm = P5Engine.getInstance().getAudio().loadMusic(gameTracks[currentTrackIndex]);
        if (currentBgm != null) {
            // Observer: when this track finishes, play the next one
            currentBgm.setOnComplete(() -> {
                stopBgm();
                playTrack(currentTrackIndex + 1);
            });
            currentBgm.play();
        }
    }

    public static void playClick() { TdAssets.playSfx(SFX_CLICK); }
    public static void playShot()  { TdAssets.playSfx(SFX_SHOT); }
    public static void playPlace() { TdAssets.playSfx(SFX_PLACE); }
}
/**
 * Sci-Fi dark theme for TowerDefenseMin2.
 * Overrides DefaultTheme with a cyan/orange accent palette.
 */
public class TdTheme implements Theme {

    private float currentAlpha = 1f;
    private processing.core.PFont font;

    public void setFont(processing.core.PFont font) {
        this.font = font;
    }

    private void applyFont(PApplet g, float size) {
        if (font != null) {
            g.textFont(font);
        }
        g.textSize(size);
    }

    static final int BG_DARK   = 0xFF0E1222;
    static final int BG_PANEL  = 0xFF1A2035;
    static final int BG_TITLE  = 0xFF151B2E;
    static final int BORDER    = 0xFF2A3A55;
    static final int ACCENT    = 0xFF4A9EFF;
    static final int HIGHLIGHT = 0xFFFF8C42;
    static final int TEXT      = 0xFFE0E6F0;
    static final int TEXT_DIM  = 0xFF8899AA;
    static final int BTN_BG    = 0xFF252F45;
    static final int BTN_HOVER = 0xFF2F3D5A;
    static final int BTN_PRESS = 0xFF1A3A5C;

    // \u2500\u2500 Theme interface \u2500\u2500

    @Override
    public void drawPanel(PApplet g, float x, float y, float w, float h, boolean focused) {
        g.noStroke();
        g.fill(a(BG_PANEL));
        g.rect(x, y, w, h, 4);
        g.stroke(a(focused ? ACCENT : BORDER));
        g.strokeWeight(1);
        g.noFill();
        g.rect(x + 0.5f, y + 0.5f, w - 1, h - 1, 4);
    }

    @Override
    public void drawFrame(PApplet g, float x, float y, float w, float h) {
        g.noStroke();
        g.fill(a(BG_PANEL));
        g.rect(x, y, w, h, 4);
        g.stroke(a(ACCENT));
        g.strokeWeight(2);
        g.noFill();
        g.rect(x + 1, y + 1, w - 2, h - 2, 4);
    }

    @Override
    public void drawWindowChrome(PApplet g, float x, float y, float w, float h, float titleH, String title, boolean focused) {
        if (titleH <= 0) {
            // No title bar: just content + border
            g.noStroke();
            g.fill(a(BG_PANEL));
            g.rect(x, y, w, h, 4);
            g.stroke(a(focused ? ACCENT : BORDER));
            g.strokeWeight(1.5f);
            g.noFill();
            g.rect(x + 0.75f, y + 0.75f, w - 1.5f, h - 1.5f, 4);
            return;
        }
        // Title bar
        g.noStroke();
        g.fill(a(BG_TITLE));
        g.rect(x, y, w, titleH, 4, 4, 0, 0);
        // Content
        g.fill(a(BG_PANEL));
        g.rect(x, y + titleH - 1, w, h - titleH + 1, 0, 0, 4, 4);
        // Border glow
        g.stroke(a(focused ? ACCENT : BORDER));
        g.strokeWeight(1.5f);
        g.noFill();
        g.rect(x + 0.75f, y + 0.75f, w - 1.5f, h - 1.5f, 4);
        // Title text
        g.fill(a(TEXT));
        g.textAlign(PApplet.LEFT, PApplet.CENTER);
        applyFont(g, Math.min(16, titleH * 0.55f));
        g.text(title != null ? title : "", x + 12, y + titleH * 0.5f);

        // Control buttons (close/max/min) \u2014 simplified as small rects
        float btnW = 20, btnH = 14, btnGap = 4;
        float btnY = y + (titleH - btnH) * 0.5f;
        float btnRight = x + w - btnGap;
        // Close
        btnRight -= btnW;
        drawWinButton(g, btnRight, btnY, btnW, btnH, "\u00D7");
        // Max
        btnRight -= btnW + btnGap;
        drawWinButton(g, btnRight, btnY, btnW, btnH, "\u25A1");
        // Min
        btnRight -= btnW + btnGap;
        drawWinButton(g, btnRight, btnY, btnW, btnH, "\u2212");
    }

    private void drawWinButton(PApplet g, float x, float y, float w, float h, String label) {
        g.noStroke();
        g.fill(a(0xFF333333));
        g.rect(x, y, w, h, 2);
        g.stroke(a(BORDER));
        g.strokeWeight(1);
        g.noFill();
        g.rect(x + 0.5f, y + 0.5f, w - 1, h - 1, 2);
        g.fill(a(TEXT));
        g.textAlign(PApplet.CENTER, PApplet.CENTER);
        applyFont(g, 9);
        g.text(label, x + w * 0.5f, y + h * 0.5f);
    }

    @Override
    public void drawButton(PApplet g, float x, float y, float w, float h, String label, boolean hover, boolean pressed, boolean disabled) {
        float scale = pressed ? 0.96f : 1.0f;
        float cx = x + w * 0.5f;
        float cy = y + h * 0.5f;

        g.pushMatrix();
        g.translate(cx, cy);
        g.scale(scale);
        g.translate(-cx, -cy);

        int fill = disabled ? 0xFF333333 : (pressed ? BTN_PRESS : (hover ? BTN_HOVER : BTN_BG));
        float r = 6;
        g.noStroke();
        g.fill(a(fill));
        g.rect(x, y, w, h, r);

        // Glow border on hover
        if (hover && !disabled) {
            g.stroke(a(ACCENT));
            g.strokeWeight(2);
            g.noFill();
            g.rect(x + 1, y + 1, w - 2, h - 2, r);
            // Subtle inner glow
            g.stroke(a(ACCENT & 0x40FFFFFF));
            g.strokeWeight(1);
            g.rect(x + 2, y + 2, w - 4, h - 4, r - 1);
        } else {
            g.stroke(a(disabled ? BORDER : BORDER));
            g.strokeWeight(1);
            g.noFill();
            g.rect(x + 0.5f, y + 0.5f, w - 1, h - 1, r);
        }

        g.fill(a(disabled ? TEXT_DIM : (hover ? 0xFFFFFFFF : TEXT)));
        g.textAlign(PApplet.CENTER, PApplet.CENTER);
        applyFont(g, Math.min(18, h * 0.48f));
        g.text(label != null ? label : "", x + w * 0.5f, y + h * 0.5f);

        g.popMatrix();
    }

    @Override
    public void drawCheckbox(PApplet g, float x, float y, float w, float h, String label, boolean checked, boolean hover, boolean disabled) {
        float box = Math.min(h - 6, 16);
        float bx = x + 4;
        float by = y + (h - box) * 0.5f;
        g.stroke(a(disabled ? BORDER : (hover ? ACCENT : BORDER)));
        g.strokeWeight(1);
        g.fill(a(disabled ? 0xFF333333 : BG_DARK));
        g.rect(bx, by, box, box, 2);
        if (checked) {
            g.stroke(a(ACCENT));
            g.line(bx + 3, by + box * 0.5f, bx + box * 0.35f, by + box - 3);
            g.line(bx + box * 0.35f, by + box - 3, bx + box - 2, by + 2);
        }
        g.fill(a(disabled ? TEXT_DIM : TEXT));
        g.noStroke();
        g.textAlign(PApplet.LEFT, PApplet.CENTER);
        applyFont(g, Math.min(14, h * 0.45f));
        g.text(label != null ? label : "", bx + box + 8, y + h * 0.5f);
    }

    @Override
    public void drawRadio(PApplet g, float x, float y, float w, float h, String label, boolean selected, boolean hover, boolean disabled) {
        float r = Math.min(h - 6, 14) * 0.5f;
        float cx = x + 4 + r;
        float cy = y + h * 0.5f;
        g.stroke(a(disabled ? BORDER : (hover ? ACCENT : BORDER)));
        g.strokeWeight(1);
        g.fill(a(disabled ? 0xFF333333 : BG_DARK));
        g.ellipse(cx, cy, r * 2, r * 2);
        if (selected) {
            g.noStroke();
            g.fill(a(ACCENT));
            g.ellipse(cx, cy, r * 1.1f, r * 1.1f);
        }
        g.fill(a(disabled ? TEXT_DIM : TEXT));
        g.textAlign(PApplet.LEFT, PApplet.CENTER);
        applyFont(g, Math.min(14, h * 0.45f));
        g.text(label != null ? label : "", x + 4 + r * 2 + 10, y + h * 0.5f);
    }

    @Override
    public void drawLabel(PApplet g, float x, float y, float w, float h, String text, boolean disabled, int textAlign) {
        g.fill(a(disabled ? TEXT_DIM : TEXT));
        g.noStroke();
        g.textAlign(textAlign, PApplet.CENTER);
        applyFont(g, Math.min(14, h * 0.5f));
        g.text(text != null ? text : "", x, y, w, h);
    }

    @Override
    public void drawTextField(PApplet g, float x, float y, float w, float h, String text, int caretIndex, boolean focused, boolean disabled) {
        g.stroke(a(disabled ? BORDER : (focused ? ACCENT : BORDER)));
        g.strokeWeight(1);
        g.fill(a(disabled ? 0xFF333333 : BG_DARK));
        g.rect(x, y, w, h, 3);
        g.fill(a(disabled ? TEXT_DIM : TEXT));
        g.noStroke();
        g.textAlign(PApplet.LEFT, PApplet.CENTER);
        float textSize = Math.min(14, h * 0.45f);
        applyFont(g, textSize);
        String t = text != null ? text : "";
        g.text(t, x + 6, y + h * 0.5f);
        if (focused && !disabled) {
            int ci = caretIndex < 0 ? t.length() : Math.min(caretIndex, t.length());
            String prefix = t.substring(0, ci);
            float tw = g.textWidth(prefix);
            g.stroke(a(ACCENT));
            g.line(x + 6 + tw, y + 6, x + 6 + tw, y + h - 6);
        }
    }

    @Override
    public void drawSliderTrack(PApplet g, float x, float y, float w, float h, float value01, boolean hover, boolean disabled) {
        float v = Math.max(0, Math.min(1, value01));
        g.noStroke();
        g.fill(a(disabled ? 0xFF333333 : 0xFF252525));
        g.rect(x, y + h * 0.35f, w, h * 0.3f, 2);
        g.fill(a(disabled ? BORDER : ACCENT));
        g.rect(x, y + h * 0.35f, w * v, h * 0.3f, 2);
        float knobX = x + w * v;
        g.stroke(a(hover && !disabled ? ACCENT : BORDER));
        g.strokeWeight(1);
        g.fill(a(disabled ? 0xFF555555 : 0xFFCCCCCC));
        g.ellipse(knobX, y + h * 0.5f, h * 0.55f, h * 0.55f);
    }

    @Override
    public void drawScrollBar(PApplet g, float x, float y, float w, float h, float thumbStart, float thumbLen, boolean vertical, boolean hover, boolean disabled) {
        g.noStroke();
        g.fill(a(0xFF222222));
        g.rect(x, y, w, h, 2);
        g.fill(a(disabled ? 0xFF555555 : (hover ? 0xFF777777 : 0xFF666666)));
        if (vertical) {
            g.rect(x + 1, y + thumbStart, w - 2, Math.max(8, thumbLen), 2);
        } else {
            g.rect(x + thumbStart, y + 1, Math.max(8, thumbLen), h - 2, 2);
        }
    }

    @Override
    public void drawProgressBar(PApplet g, float x, float y, float w, float h, float value01, boolean disabled) {
        float v = Math.max(0, Math.min(1, value01));
        g.noStroke();
        g.fill(a(disabled ? 0xFF333333 : 0xFF252525));
        g.rect(x, y, w, h, 3);
        g.fill(a(disabled ? BORDER : ACCENT));
        g.rect(x, y, w * v, h, 3);
        g.stroke(a(BORDER));
        g.strokeWeight(1);
        g.noFill();
        g.rect(x + 0.5f, y + 0.5f, w - 1, h - 1, 3);
    }

    @Override
    public void drawList(PApplet g, float x, float y, float w, float h, java.util.List<String> items, int firstIndex, int selectedIndex, boolean focused, boolean disabled) {
        g.stroke(a(disabled ? BORDER : (focused ? ACCENT : BORDER)));
        g.strokeWeight(1);
        g.fill(a(BG_DARK));
        g.rect(x, y, w, h, 3);
        g.textAlign(PApplet.LEFT, PApplet.CENTER);
        applyFont(g, 13);
        float rowH = 26;
        int idx = 0;
        for (int i = firstIndex; i < items.size(); i++) {
            float ry = y + idx * rowH;
            if (ry + rowH > y + h) break;
            if (i == selectedIndex) {
                g.noStroke();
                g.fill(a(0xFF2A4A6A));
                g.rect(x + 1, ry, w - 2, rowH, 2);
            }
            g.fill(a(disabled ? TEXT_DIM : TEXT));
            g.noStroke();
            g.text(items.get(i), x + 6, ry + rowH * 0.5f);
            idx++;
        }
    }

    @Override
    public void drawTabHeader(PApplet g, float x, float y, float w, float h, String[] titles, int selected, boolean focused) {
        if (titles == null || titles.length == 0) return;
        float tw = w / titles.length;
        for (int i = 0; i < titles.length; i++) {
            float tx = x + i * tw;
            boolean sel = i == selected;
            g.noStroke();
            g.fill(a(sel ? BG_PANEL : 0xFF2A2A2A));
            g.rect(tx, y, tw, h, 3, 3, 0, 0);
            g.stroke(a(focused && sel ? ACCENT : BORDER));
            g.strokeWeight(1);
            g.noFill();
            g.rect(tx + 0.5f, y + 0.5f, tw - 1, h - 1, 3, 3, 0, 0);
            g.fill(a(TEXT));
            g.textAlign(PApplet.CENTER, PApplet.CENTER);
            applyFont(g, Math.min(13, h * 0.45f));
            g.text(titles[i], tx + tw * 0.5f, y + h * 0.5f);
        }
    }

    @Override
    public void drawImage(PApplet g, float x, float y, float w, float h, processing.core.PImage img, boolean disabled) {
        if (img == null) {
            g.noStroke();
            g.fill(a(0xFF333333));
            g.rect(x, y, w, h, 3);
            return;
        }
        g.pushStyle();
        int baseAlpha = Math.round(255 * currentAlpha);
        if (disabled) {
            g.tint(255, Math.round(baseAlpha * 120f / 255f));
        } else if (currentAlpha < 1f) {
            g.tint(255, baseAlpha);
        }
        g.image(img, x, y, w, h);
        g.popStyle();
    }

    @Override
    public void setCurrentAlpha(float alpha) {
        this.currentAlpha = Math.max(0f, Math.min(1f, alpha));
    }

    private int a(int c) {
        if (currentAlpha >= 1f) return c;
        int origA = (c >>> 24) & 0xFF;
        int newA = Math.round(origA * currentAlpha);
        return (newA << 24) | (c & 0x00FFFFFF);
    }
}
/**
 * HUD UI components using p5engine UI library.
 * Replaces hand-drawn TdHUD and TdMinimap.
 */

// \u2500\u2500\u2500 Tower Button \u2500\u2500\u2500

static class TowerButton extends Button {
    TowerType towerType;
    String initial;

    TowerButton(String id, TowerType type, String initial) {
        super(id);
        this.towerType = type;
        this.initial = initial;
        setSize(TdConfig.RIGHT_W - 16, 56);
    }

    @Override
    public void paint(PApplet applet, Theme theme) {
        TowerDef def = TdAssets.loadTowerDef(towerType);
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        boolean selected = (app.buildMode == TowerType.toBuildMode(towerType));

        float scale = (pressedVisual || selected) ? 0.94f : 1.0f;
        float cx = getAbsoluteX() + getWidth() * 0.5f;
        float cy = getAbsoluteY() + getHeight() * 0.5f;

        applet.pushMatrix();
        applet.translate(cx, cy);
        applet.scale(scale);
        applet.translate(-cx, -cy);

        int fill = selected ? TdTheme.BTN_PRESS : (hover ? TdTheme.BTN_HOVER : TdTheme.BTN_BG);
        applet.noStroke();
        applet.fill(fill);
        applet.rect(getAbsoluteX(), getAbsoluteY(), getWidth(), getHeight());

        applet.stroke(selected ? TdTheme.ACCENT : TdTheme.BORDER);
        applet.strokeWeight(selected ? 2 : 1);
        applet.noFill();
        applet.rect(getAbsoluteX() + 0.5f, getAbsoluteY() + 0.5f, getWidth() - 1, getHeight() - 1);

        // Icon
        float iconSize = 32;
        float iconX = getAbsoluteX() + 8;
        float iconY = getAbsoluteY() + (getHeight() - iconSize) * 0.5f;
        applet.noStroke();
        applet.fill(TdConfig.C_ACCENT);
        applet.rect(iconX, iconY, iconSize, iconSize);
        applet.fill(TdTheme.BG_DARK);
        applet.textAlign(PApplet.CENTER, PApplet.CENTER);
        applet.textSize(14);
        applet.text(initial, iconX + iconSize * 0.5f, iconY + iconSize * 0.5f);

        // Name and cost
        if (def != null) {
            applet.fill(TdTheme.TEXT);
            applet.textAlign(PApplet.LEFT, PApplet.CENTER);
            applet.textSize(13);
            applet.text(TdAssets.i18n(def.nameKey), iconX + iconSize + 10, getAbsoluteY() + getHeight() * 0.35f);
            applet.fill(TdTheme.TEXT_DIM);
            applet.textSize(11);
            applet.text("$" + def.cost, iconX + iconSize + 10, getAbsoluteY() + getHeight() * 0.7f);
        }

        applet.popMatrix();
    }

    @Override
    public void update(PApplet applet, float dt) {
        super.update(applet, dt);
        TowerDef def = TdAssets.loadTowerDef(towerType);
        if (def != null) {
            setEnabled(TdGameWorld.money >= def.cost);
        }
    }
}

// \u2500\u2500\u2500 Minimap Component \u2500\u2500\u2500

static class TdMinimapComponent extends UIComponent {
    static final float MW = 180, MH = 120;

    TdMinimapComponent(String id) {
        super(id);
        setSize(MW, MH);
    }

    @Override
    public void paint(PApplet applet, Theme theme) {
        float mx = getAbsoluteX();
        float my = getAbsoluteY();

        applet.pushStyle();
        applet.noStroke();
        applet.fill(TdTheme.BG_DARK);
        applet.rect(mx, my, MW, MH);
        applet.stroke(TdTheme.BORDER);
        applet.strokeWeight(1);
        applet.noFill();
        applet.rect(mx + 0.5f, my + 0.5f, MW - 1, MH - 1);

        if (TdGameWorld.level != null) {
            float sx = MW / TdGameWorld.level.worldW;
            float sy = MH / TdGameWorld.level.worldH;

            // Base
            applet.fill(0xFF4A9EFF);
            applet.ellipse(mx + TdGameWorld.level.basePos.x * sx, my + TdGameWorld.level.basePos.y * sy, 6, 6);
            // Exit
            applet.fill(0xFFFF4444);
            applet.ellipse(mx + TdGameWorld.level.exitPos.x * sx, my + TdGameWorld.level.exitPos.y * sy, 6, 6);
            // Path \u2014 draw all routes (multi-path) or legacy pathPoints
            applet.stroke(0xFF4A9EFF);
            applet.strokeWeight(1);
            if (TdGameWorld.level.paths != null && TdGameWorld.level.paths.length > 0) {
                for (PathRoute pr : TdGameWorld.level.paths) {
                    if (pr.path == null || pr.path.points == null || pr.path.points.length < 2) continue;
                    Vector2[] pts = pr.path.points;
                    for (int i = 1; i < pts.length; i++) {
                        applet.line(mx + pts[i-1].x * sx, my + pts[i-1].y * sy,
                                    mx + pts[i].x * sx, my + pts[i].y * sy);
                    }
                }
            } else if (TdGameWorld.level.pathPoints != null) {
                Vector2[] pts = TdGameWorld.level.pathPoints;
                for (int i = 1; i < pts.length; i++) {
                    applet.line(mx + pts[i-1].x * sx, my + pts[i-1].y * sy,
                                mx + pts[i].x * sx, my + pts[i].y * sy);
                }
            }
            // Towers
            applet.noStroke();
            applet.fill(0xFF66FF66);
            for (Tower t : TdGameWorld.towers) {
                applet.rect(mx + t.worldX * sx - 4, my + t.worldY * sy - 4, 6, 6);
            }
            // Enemies
            applet.noStroke();
            applet.fill(0xFFFF4444);
            for (Enemy e : TdGameWorld.enemies) {
                applet.ellipse(mx + e.pos.x * sx, my + e.pos.y * sy, 5, 5);
            }
            // Camera rect
            TowerDefenseMin2 app = TowerDefenseMin2.inst;
            Camera2D cam = app.camera;
            if (cam != null) {
                float cx = cam.getTransform().getPosition().x;
                float cy = cam.getTransform().getPosition().y;
                float cw = cam.getViewportWidth() / cam.getZoom();
                float ch = cam.getViewportHeight() / cam.getZoom();
                applet.noFill();
                applet.stroke(0xFFFF8C42);
                applet.strokeWeight(1);
                applet.rect(mx + (cx - cw * 0.5f) * sx, my + (cy - ch * 0.5f) * sy, cw * sx, ch * sy);
            }
        }
        applet.popStyle();
    }

    @Override
    public boolean onEvent(UIEvent event, float absMouseX, float absMouseY) {
        if (event.getMouseButton() != PApplet.LEFT) return false;
        switch (event.getType()) {
            case MOUSE_PRESSED:
            case MOUSE_DRAGGED:
                jumpCameraTo(absMouseX, absMouseY);
                return true;
            case MOUSE_RELEASED:
                return true;
            default:
                return false;
        }
    }

    public void jumpCameraTo(float absMouseX, float absMouseY) {
        if (TdGameWorld.level == null) return;
        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        if (app.camera == null) return;
        float mx = getAbsoluteX();
        float my = getAbsoluteY();
        float wx = (absMouseX - mx) / MW * TdGameWorld.level.worldW;
        float wy = (absMouseY - my) / MH * TdGameWorld.level.worldH;
        app.camera.jumpCenterTo(wx, wy);
    }
}

// \u2500\u2500\u2500 Top Bar \u2500\u2500\u2500

static class TdTopBar extends Panel {
    Label lblStatus;
    Button btnRange;

    TdTopBar(String id) {
        super(id);
        setPaintBackground(true);
        setBounds(0, 0, 1280, TdConfig.TOP_HUD);
        setLayoutManager(null);

        lblStatus = new Label("lbl_status");
        lblStatus.setBounds(16, 0, 400, TdConfig.TOP_HUD);
        lblStatus.setTextAlign(PApplet.LEFT);
        add(lblStatus);

        btnRange = new Button("btn_range");
        btnRange.setBounds(1280 - 72 - 12 - 80 - 8, (TdConfig.TOP_HUD - 28) * 0.5f, 80, 28);
        btnRange.setAction(() -> {
            TowerDefenseMin2 app = TowerDefenseMin2.inst;
            app.showTowerRanges = !app.showTowerRanges;
        });
        add(btnRange);

        Button btnPause = new Button("btn_pause");
        btnPause.setLabel(TdAssets.i18n("game.pause"));
        btnPause.setBounds(1280 - 72 - 12, (TdConfig.TOP_HUD - 28) * 0.5f, 72, 28);
        btnPause.setAction(() -> {
            TowerDefenseMin2 app = TowerDefenseMin2.inst;
            if (app.state == TdState.PLAYING) {
                app.state = TdState.PAUSED;
            } else if (app.state == TdState.PAUSED) {
                app.state = TdState.PLAYING;
            }
        });
        add(btnPause);
    }

    @Override
    public void update(PApplet applet, float dt) {
        super.update(applet, dt);
        String statusText;
        if (TdGameWorld.level != null && TdGameWorld.level.levelType == LevelType.SURVIVAL) {
            statusText = "$ " + TdGameWorld.money + "  \u9003 " + TdGameWorld.escapedEnemies + "/" + TdGameWorld.level.maxEscapeCount
                + "  \u6ce2 " + TdGameWorld.currentWave + "/" + TdGameWorld.level.waves.length;
        } else {
            statusText = "$ " + TdGameWorld.money + "  \u2666 " + TdGameWorld.orbits
                + "  \u6ce2 " + TdGameWorld.currentWave + "/" + (TdGameWorld.level != null ? TdGameWorld.level.waves.length : 0);
        }
        lblStatus.setText(statusText);

        TowerDefenseMin2 app = TowerDefenseMin2.inst;
        boolean active = app.showTowerRanges || app.buildMode != TdBuildMode.NONE;
        btnRange.setLabel(TdAssets.i18n(active ? "game.rangeOn" : "game.rangeOff"));
    }
}

// \u2500\u2500\u2500 Build Panel \u2500\u2500\u2500

static class TdBuildPanel extends Panel {
    TowerType[] allTypes = { TowerType.MG, TowerType.MISSILE, TowerType.LASER, TowerType.SLOW };
    String[] allInitials = { "M", "R", "L", "S" };

    TdBuildPanel(String id) {
        super(id);
        setPaintBackground(true);
        setBounds(1280 - TdConfig.RIGHT_W, TdConfig.TOP_HUD, TdConfig.RIGHT_W, 720 - TdConfig.TOP_HUD);
        setLayoutManager(null);
        rebuildButtons();
    }

    public void rebuildButtons() {
        removeAllChildren();

        TowerType[] allowed = (TdGameWorld.level != null && TdGameWorld.level.allowedTowers != null)
            ? TdGameWorld.level.allowedTowers : allTypes;

        float by = 16;
        for (int i = 0; i < allTypes.length; i++) {
            TowerType tt = allTypes[i];
            boolean isAllowed = false;
            for (TowerType a : allowed) {
                if (a == tt) { isAllowed = true; break; }
            }
            if (!isAllowed) continue;

            final TdBuildMode mode = TowerType.toBuildMode(tt);
            TowerButton btn = new TowerButton("btn_" + tt.name().toLowerCase(), tt, allInitials[i]);
            btn.setPosition(8, by);
            btn.setSfxPath(TdSound.SFX_TOWER_SELECT);
            btn.setAction(() -> {
                TowerDefenseMin2 app = TowerDefenseMin2.inst;
                app.buildMode = mode;
            });
            add(btn);
            by += 56 + 8;
        }

        by += 8;
        Button btnCancel = new Button("btn_cancel");
        btnCancel.setLabel(TdAssets.i18n("game.build.cancel"));
        btnCancel.setBounds(8, by, TdConfig.RIGHT_W - 16, 32);
        btnCancel.setAction(() -> {
            TowerDefenseMin2 app = TowerDefenseMin2.inst;
            app.buildMode = TdBuildMode.NONE;
        });
        add(btnCancel);
    }
}
/**
 * Wave data & timing \u2014 handled inside TdGameWorld.
 * This file reserved for future wave composition logic (mixed enemy types, etc.)
 */
static final class TdWave {
    int waveNumber;
    int enemyCount;
    float hpMultiplier;
    float speedMultiplier;
    String[] enemyTypes;
}
/**
 * Active tower instance in the game world.
 */
static class Tower {
    TowerDef def;
    int gridX, gridY;
    float worldX, worldY;
    float cooldown;
    float buildProgress;
    boolean built;
    GameObject gameObject;

    Tower(TowerDef def, int gx, int gy) {
        this.def = def;
        this.gridX = gx;
        this.gridY = gy;
        this.worldX = (gx + 0.5f) * TdConfig.GRID;
        this.worldY = (gy + 0.5f) * TdConfig.GRID;
        this.cooldown = 0;
        this.buildProgress = 0;
        this.built = false;
    }

    public void update(float dt) {
        if (!built) {
            buildProgress += dt;
            if (buildProgress >= def.buildTime) {
                built = true;
                TdAssets.playSfx(def.sfxComplete);
            }
            return;
        }
        cooldown -= dt;
        if (cooldown <= 0) {
            Enemy target = findTarget();
            if (target != null) {
                fireAt(target);
                cooldown = def.firePeriod;
            }
        }
    }

    public Enemy findTarget() {
        Enemy best = null;
        float bestPathDist = -1;
        Vector2 towerPos = new Vector2(worldX, worldY);
        for (Enemy e : TdGameWorld.enemies) {
            if (e.hp <= 0) continue;
            float d = e.pos.distance(towerPos);
            if (d <= def.range && e.routeProgress > bestPathDist) {
                bestPathDist = e.routeProgress;
                best = e;
            }
        }
        return best;
    }

    public void fireAt(Enemy target) {
        TowerDefenseMin2 app = TowerDefenseMin2.inst;

        // Acquire from object pools
        Bullet b = app.bulletDataPool.acquire();
        GameObject bGo = app.bulletGoPool.acquire();
        bGo.setActive(true);

        // Bind renderer
        BulletRenderer renderer = bGo.getComponent(BulletRenderer.class);
        renderer.bullet = b;

        // Initialize bullet data
        Vector2 dir = target.pos.copy().sub(worldX, worldY).normalize().mult(400);
        b.reset(worldX, worldY, dir.x, dir.y, def.damage, def.aoeRadius, def.laserBonus, def.slowFactor);
        b.gameObject = bGo;
        bGo.getTransform().setPosition(b.pos.x, b.pos.y);

        TdGameWorld.bullets.add(b);
        TdAssets.playSfx(def.sfxFire);
    }
}


  static public void main(String[] passedArgs) {
    String[] appletArgs = new String[] { "TowerDefenseMin2" };
    if (passedArgs != null) {
      PApplet.main(concat(appletArgs, passedArgs));
    } else {
      PApplet.main(appletArgs);
    }
  }
